import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { 
  Plus, Loader2, ImageIcon, Sparkles, Trash, ArrowLeft, 
  Eye, X, ShoppingBasket, Edit2, Check, Calendar, Package, Tag
} from 'lucide-react';
import SubirImagenes from './SubirImagenes'; 

const API_URL = "http://localhost:5000"; 
const CLOUD_NAME = "dwpgncjgn";

const GestionOfertas = () => {
  const { id: localId } = useParams();
  const navigate = useNavigate();

  const filaInicial = () => ({ 
    id: Math.random(), 
    producto: '', 
    precioNuevo: '', 
    precioViejo: '', 
    stock: '', 
    categoria: 'Almacén', 
    fotoSugerida: null 
  });
  
  const [filas, setFilas] = useState([filaInicial()]);
  const [publicados, setPublicados] = useState([]);
  const [galeria, setGaleria] = useState([]);
  const [fechas, setFechas] = useState({ inicio: '', fin: '' });
  const [cargando, setCargando] = useState(false);
  const [mostrarGaleria, setMostrarGaleria] = useState(false);
  
  // ESTADOS PARA EDICIÓN INDIVIDUAL
  const [editandoId, setEditandoId] = useState(null);
  const [formEdit, setFormEdit] = useState({});

  const cargarDatos = useCallback(async () => {
    try {
      const [resOfertas, resGaleria] = await Promise.all([
        axios.get(`${API_URL}/api/ofertas/local/${localId}`),
        axios.get(`${API_URL}/api/galeria`)
      ]);
      setPublicados(resOfertas.data || []);
      setGaleria(resGaleria.data || []);
    } catch (e) { console.error("Error al sincronizar", e); }
  }, [localId]);

  useEffect(() => { cargarDatos(); }, [cargarDatos]);

  const buscarMatch = useCallback((texto) => {
    if (!texto || texto.length < 3) return null;
    const norm = (t) => t.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/[^a-z0-9]/g, '');
    const textoLimpio = norm(texto);
    return galeria.find(f => {
      const refLimpia = norm(f.nombreReferencia.split('.')[0]); 
      return refLimpia.includes(textoLimpio) || textoLimpio.includes(refLimpia);
    });
  }, [galeria]);

  const handlePaste = (e) => {
    const pasteData = e.clipboardData.getData('text');
    if (pasteData.includes('\t') || pasteData.includes('\n')) {
      e.preventDefault();
      const lineas = pasteData.split(/\r?\n/).filter(l => l.trim() !== '');
      const nuevasFilas = lineas.map(line => {
        const columnas = line.split('\t');
        const nombre = columnas[0]?.trim() || '';
        const match = buscarMatch(nombre);
        return {
          id: Math.random(),
          producto: nombre,
          precioNuevo: columnas[1]?.replace(/[^0-9.]/g, '') || '',
          precioViejo: columnas[2]?.replace(/[^0-9.]/g, '') || '',
          stock: columnas[3]?.replace(/[^0-9]/g, '') || '0',
          categoria: columnas[4]?.trim() || 'Almacén',
          fotoSugerida: match ? match.publicId : null
        };
      });
      setFilas(nuevasFilas);
    }
  };

  const handleInputChange = (id, campo, valor) => {
    setFilas(filas.map(f => {
      if (f.id === id) {
        const act = { ...f, [campo]: valor };
        if (campo === 'producto') {
          const m = buscarMatch(valor);
          act.fotoSugerida = m ? m.publicId : null;
        }
        return act;
      }
      return f;
    }));
  };

  const publicarTodo = async () => {
    if (!fechas.inicio || !fechas.fin) return alert("Selecciona fechas de validez.");
    const validas = filas.filter(f => f.producto && f.precioNuevo);
    if (validas.length === 0) return alert("No hay productos válidos.");

    setCargando(true);
    try {
      const productos = validas.map(f => ({
        ...f,
        publicId: f.fotoSugerida || 'placeholder_id',
        fechaInicioOferta: fechas.inicio,
        fechaFinOferta: fechas.fin,
        publicado: true
      }));
      await axios.post(`${API_URL}/api/ofertas/bulk`, { localId, productos });
      setFilas([filaInicial()]);
      cargarDatos();
      alert("¡Inventario actualizado con éxito!");
    } catch (e) { alert("Error al publicar."); } finally { setCargando(false); }
  };

  // GUARDAR EDICIÓN INDIVIDUAL
  const guardarEdicion = async (id) => {
    try {
      await axios.put(`${API_URL}/api/ofertas/${id}`, formEdit);
      setEditandoId(null);
      cargarDatos();
    } catch (e) { alert("Error al actualizar el producto"); }
  };

  const renderFoto = (pid, size = "w_150,h_150") => {
    if (!pid || pid === 'placeholder_id') return <div style={thumbPlaceholder}><ImageIcon color="#cbd5e1" size={20}/></div>;
    const urlFinal = `https://res.cloudinary.com/${CLOUD_NAME}/image/upload/${size},c_fill,f_auto,q_auto/${pid}`;
    return (
      <div style={thumbWrap}>
        <img src={urlFinal} style={imgStyle} alt="Producto" />
      </div>
    );
  };

  const tandas = publicados.reduce((acc, p) => {
    const fecha = p.fechaFinOferta ? new Date(p.fechaFinOferta).toLocaleDateString() : 'Sin Fecha';
    if (!acc[fecha]) acc[fecha] = [];
    acc[fecha].push(p);
    return acc;
  }, {});

  return (
    <div style={containerStyle}>
      <div style={navStyle}>
        <button onClick={() => navigate(-1)} style={btnBack}><ArrowLeft size={18}/> Volver al Mapa</button>
        <div style={{ display: 'flex', gap: '12px' }}>
            <button onClick={() => setMostrarGaleria(!mostrarGaleria)} style={btnVerGaleria}><Eye size={18}/> {mostrarGaleria ? "Cerrar Galería" : "Ver Biblioteca"}</button>
            <SubirImagenes onFinished={cargarDatos} />
        </div>
      </div>

      <header style={{ marginBottom: '30px' }}>
        <h1 style={titleStyle}><ShoppingBasket color="#e67e22" size={32}/> Gestión de Inventario</h1>
        <p style={{color: '#64748b'}}>Carga rápida vía Excel y control de stock individual.</p>
      </header>

      {/* CARGA MASIVA */}
      <section style={cardContainer}>
        <div style={cardHeader}>
          <div style={{ color: '#e67e22', fontWeight: 'bold', display:'flex', gap:8 }}><Sparkles size={20}/> Pegado de Excel</div>
          <button onClick={() => setFilas([...filas, filaInicial()])} style={btnAddRow}><Plus size={16}/> Fila Manual</button>
        </div>
        <div style={{overflowX: 'auto'}}>
          <table style={tableStyle}>
            <thead>
              <tr style={tableHead}>
                <th style={thStyle}>Foto</th>
                <th style={thStyle}>Producto</th>
                <th style={thStyle}>$ Oferta</th>
                <th style={thStyle}>$ Viejo</th>
                <th style={thStyle}>Stock</th>
                <th style={thStyle}>Categoría</th>
                <th style={{width: 50}}></th>
              </tr>
            </thead>
            <tbody>
              {filas.map(f => (
                <tr key={f.id} style={trStyle}>
                  <td style={tdStyle}>{renderFoto(f.fotoSugerida)}</td>
                  <td style={tdStyle}><input style={inputTable} value={f.producto} onPaste={handlePaste} onChange={e => handleInputChange(f.id, 'producto', e.target.value)} placeholder="Producto..."/></td>
                  <td style={tdStyle}><input style={inputNum} value={f.precioNuevo} onChange={e => handleInputChange(f.id, 'precioNuevo', e.target.value)} placeholder="0"/></td>
                  <td style={tdStyle}><input style={inputNum} value={f.precioViejo} onChange={e => handleInputChange(f.id, 'precioViejo', e.target.value)} placeholder="0"/></td>
                  <td style={tdStyle}><input style={inputNum} value={f.stock} onChange={e => handleInputChange(f.id, 'stock', e.target.value)} placeholder="0"/></td>
                  <td style={tdStyle}><input style={inputTable} value={f.categoria} onChange={e => handleInputChange(f.id, 'categoria', e.target.value)}/></td>
                  <td style={tdStyle}><button onClick={() => setFilas(filas.filter(x => x.id !== f.id))} style={btnX}><X size={18}/></button></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        <div style={cardFooter}>
          <div style={{ display: 'flex', gap: 10, alignItems: 'center' }}>
            <Calendar size={18} color="#64748b"/>
            <input type="date" value={fechas.inicio} onChange={e => setFechas({...fechas, inicio: e.target.value})} style={inputDate}/>
            <span style={{color: '#94a3b8'}}>hasta</span>
            <input type="date" value={fechas.fin} onChange={e => setFechas({...fechas, fin: e.target.value})} style={inputDate}/>
          </div>
          <button onClick={publicarTodo} style={btnPublish} disabled={cargando}>
            {cargando ? <Loader2 className="animate-spin"/> : "PUBLICAR TODO"}
          </button>
        </div>
      </section>

      {/* TARJETAS DE PRODUCTOS PUBLICADOS */}
      <h2 style={{fontSize:'1.2rem', color:'#1e293b', marginBottom:'20px'}}>Ofertas Activas</h2>
      {Object.keys(tandas).map(fecha => (
        <div key={fecha} style={{ marginBottom: '40px' }}>
          <div style={tandaHeader}>Vencimiento: {fecha}</div>
          <div style={gridStyle}>
            {tandas[fecha].map(p => (
              <div key={p._id} style={itemCard}>
                {editandoId === p._id ? (
                  /* MODO EDICIÓN INDIVIDUAL */
                  <div style={editForm}>
                    <label style={labelEdit}>Nombre</label>
                    <input style={inputEdit} value={formEdit.producto} onChange={e => setFormEdit({...formEdit, producto: e.target.value})}/>
                    
                    <div style={{display:'flex', gap:10}}>
                        <div style={{flex:1}}>
                            <label style={labelEdit}>$ Oferta</label>
                            <input style={inputEdit} type="number" value={formEdit.precioNuevo} onChange={e => setFormEdit({...formEdit, precioNuevo: e.target.value})}/>
                        </div>
                        <div style={{flex:1}}>
                            <label style={labelEdit}>$ Viejo</label>
                            <input style={inputEdit} type="number" value={formEdit.precioViejo} onChange={e => setFormEdit({...formEdit, precioViejo: e.target.value})}/>
                        </div>
                    </div>

                    <div style={{display:'flex', gap:10}}>
                        <div style={{flex:1}}>
                            <label style={labelEdit}>Stock</label>
                            <input style={inputEdit} type="number" value={formEdit.stock} onChange={e => setFormEdit({...formEdit, stock: e.target.value})}/>
                        </div>
                        <div style={{flex:1}}>
                            <label style={labelEdit}>Sector</label>
                            <input style={inputEdit} value={formEdit.categoria} onChange={e => setFormEdit({...formEdit, categoria: e.target.value})}/>
                        </div>
                    </div>

                    <div style={{display:'flex', gap:10, marginTop:10}}>
                        <button onClick={() => guardarEdicion(p._id)} style={btnSave}><Check size={16}/> Guardar</button>
                        <button onClick={() => setEditandoId(null)} style={btnCancel}>Cancelar</button>
                    </div>
                  </div>
                ) : (
                  /* MODO VISTA NORMAL */
                  <>
                    <div style={itemActions}>
                      <button onClick={() => { setEditandoId(p._id); setFormEdit(p); }} style={btnEdit}><Edit2 size={14}/></button>
                      <button onClick={async () => { if(window.confirm("¿Borrar?")){ await axios.delete(`${API_URL}/api/ofertas/${p._id}`); cargarDatos(); }}} style={btnDel}><Trash size={14}/></button>
                    </div>
                    
                    <div style={itemPreview}>{renderFoto(p.publicId, "w_200,h_200")}</div>
                    
                    <div style={{display:'flex', justifyContent:'center', marginBottom:5}}>
                        <span style={catBadge}>{p.categoria}</span>
                    </div>

                    <h4 style={itemTitle}>{p.producto}</h4>
                    
                    <div style={priceContainer}>
                        <span style={oldPrice}>${p.precioViejo}</span>
                        <span style={newPrice}>${p.precioNuevo}</span>
                    </div>

                    <div style={stockBadge(p.stock)}>
                        <Package size={14}/> Stock: {p.stock} un.
                    </div>
                  </>
                )}
              </div>
            ))}
          </div>
        </div>
      ))}
    </div>
  );
};

